{
  "name": "Pentagrama Maestro",
  "description": "Una aplicación interactiva para practicar lectura musical en clave de Sol y Fa, generando notas aleatorias y permitiendo la exportación a PDF."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type Clef = 'treble' | 'bass';

export type NoteDuration = 'w' | 'h' | 'q'; // whole (redonda), half (blanca), quarter (negra)

export interface MusicNote {
  keys: string[];
  duration: NoteDuration;
}

export interface GeneratorConfig {
  clef: Clef;
  includeRedondas: boolean;
  includeBlancas: boolean;
  includeNegras: boolean;
  count: number;
}

export const TREBLE_NOTES = [
  'c/4', 'd/4', 'e/4', 'f/4', 'g/4', 'a/4', 'b/4',
  'c/5', 'd/5', 'e/5', 'f/5', 'g/5'
];

export const BASS_NOTES = [
  'e/2', 'f/2', 'g/2', 'a/2', 'b/2',
  'c/3', 'd/3', 'e/3', 'f/3', 'g/3', 'a/3', 'b/3',
  'c/4'
];

export const DURATION_MAP: Record<string, string> = {
  'w': 'Redonda',
  'h': 'Blanca',
  'q': 'Negra'
};

import React, { useState, useCallback, useEffect, useRef } from 'react';
import { Music, FileDown, RefreshCw, Info, Settings, Lightbulb } from 'lucide-react';
import MusicSheet from './components/MusicSheet';
import Controls from './components/Controls';
import { Clef, MusicNote, GeneratorConfig } from './types';
import { TREBLE_NOTES, BASS_NOTES } from './constants';
import { GoogleGenAI } from '@google/genai';
import html2canvas from 'html2canvas';
import { jsPDF } from 'jspdf';

const App: React.FC = () => {
  const [notes, setNotes] = useState<MusicNote[]>([]);
  const [config, setConfig] = useState<GeneratorConfig>({
    clef: 'treble',
    includeRedondas: true,
    includeBlancas: true,
    includeNegras: true,
    count: 8
  });
  const [aiTip, setAiTip] = useState<string>('');
  const [isGeneratingTip, setIsGeneratingTip] = useState(false);
  const sheetRef = useRef<HTMLDivElement>(null);

  const generateNotes = useCallback(() => {
    const possibleNotes = config.clef === 'treble' ? TREBLE_NOTES : BASS_NOTES;
    const possibleDurations: string[] = [];
    if (config.includeRedondas) possibleDurations.push('w');
    if (config.includeBlancas) possibleDurations.push('h');
    if (config.includeNegras) possibleDurations.push('q');

    if (possibleDurations.length === 0) return;

    const newNotes: MusicNote[] = Array.from({ length: config.count }).map(() => ({
      keys: [possibleNotes[Math.floor(Math.random() * possibleNotes.length)]],
      duration: possibleDurations[Math.floor(Math.random() * possibleDurations.length)] as any
    }));

    setNotes(newNotes);
    fetchTip(config.clef);
  }, [config]);

  const fetchTip = async (clef: Clef) => {
    setIsGeneratingTip(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `Como profesor de música para principiantes, dame un consejo muy corto (máximo 100 caracteres) sobre cómo leer mejor la clave de ${clef === 'treble' ? 'Sol' : 'Fa'}. Sé motivador.`;
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
      });
      setAiTip(response.text || '¡Sigue practicando!');
    } catch (error) {
      console.error("Error fetching AI tip:", error);
      setAiTip("El secreto es la constancia. ¡A por ello!");
    } finally {
      setIsGeneratingTip(false);
    }
  };

  const exportPDF = async () => {
    if (!sheetRef.current) return;
    const canvas = await html2canvas(sheetRef.current);
    const imgData = canvas.toDataURL('image/png');
    const pdf = new jsPDF('l', 'mm', 'a4');
    const imgProps = pdf.getImageProperties(imgData);
    const pdfWidth = pdf.internal.pageSize.getWidth();
    const pdfHeight = (imgProps.height * pdfWidth) / imgProps.width;

    pdf.setFontSize(20);
    pdf.text(`Práctica: Clave de ${config.clef === 'treble' ? 'Sol' : 'Fa'}`, 10, 15);
    pdf.addImage(imgData, 'PNG', 0, 25, pdfWidth, pdfHeight);
    pdf.save(`pentagrama_${config.clef}.pdf`);
  };

  useEffect(() => {
    generateNotes();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  return (
    <div className="min-h-screen p-4 md:p-8 flex flex-col items-center">
      <header className="w-full max-w-4xl flex flex-col md:flex-row justify-between items-center mb-8 gap-4">
        <div>
          <h1 className="text-4xl font-bold text-slate-800 flex items-center gap-2">
            <Music className="text-indigo-600" size={36} />
            Pentagrama Maestro
          </h1>
          <p className="text-slate-500 mt-1">Practica lectura musical de forma sencilla</p>
        </div>

        <div className="flex gap-3">
          <button
            onClick={generateNotes}
            className="flex items-center gap-2 bg-indigo-600 hover:bg-indigo-700 text-white px-5 py-2.5 rounded-lg font-semibold transition shadow-md"
          >
            <RefreshCw size={20} />
            Generar Notas
          </button>
          <button
            onClick={exportPDF}
            className="flex items-center gap-2 bg-white border border-slate-200 hover:bg-slate-50 text-slate-700 px-5 py-2.5 rounded-lg font-semibold transition shadow-sm"
          >
            <FileDown size={20} />
            Guardar PDF
          </button>
        </div>
      </header>

      <main className="w-full max-w-4xl grid grid-cols-1 lg:grid-cols-4 gap-6">
        <aside className="lg:col-span-1 space-y-6">
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
            <h2 className="text-lg font-bold text-slate-800 mb-4 flex items-center gap-2">
              <Settings size={18} />
              Configuración
            </h2>
            <Controls config={config} setConfig={setConfig} />
          </div>

          <div className="bg-indigo-50 p-6 rounded-2xl border border-indigo-100">
            <h2 className="text-md font-bold text-indigo-800 mb-2 flex items-center gap-2">
              <Lightbulb size={18} />
              Consejo del Tutor
            </h2>
            <p className="text-indigo-900 text-sm italic min-h-[40px]">
              {isGeneratingTip ? 'Pensando un consejo...' : aiTip}
            </p>
          </div>
        </aside>

        <section className="lg:col-span-3">
          <div 
            ref={sheetRef}
            className="bg-white p-4 md:p-8 rounded-2xl shadow-lg border border-slate-100 flex flex-col items-center overflow-x-auto min-h-[400px]"
          >
            <h3 className="text-slate-400 font-medium self-start mb-4 uppercase tracking-wider text-xs">Partitura de práctica</h3>
            <MusicSheet notes={notes} clef={config.clef} />
            <div className="mt-8 grid grid-cols-4 gap-4 w-full text-center">
               <div className="text-xs text-slate-400 bg-slate-50 p-2 rounded">Compás: 4/4</div>
               <div className="text-xs text-slate-400 bg-slate-50 p-2 rounded">Clave: {config.clef === 'treble' ? 'Sol' : 'Fa'}</div>
               <div className="text-xs text-slate-400 bg-slate-50 p-2 rounded">Tempo: 60 BPM</div>
               <div className="text-xs text-slate-400 bg-slate-50 p-2 rounded">Nivel: Inicial</div>
            </div>
          </div>

          <div className="mt-6 bg-slate-800 text-white p-6 rounded-2xl flex items-start gap-4">
            <Info className="text-indigo-400 flex-shrink-0" size={24} />
            <div>
              <h4 className="font-bold">¿Cómo leer el pentagrama?</h4>
              <p className="text-sm text-slate-300 mt-1">
                La clave de <strong>Sol</strong> se usa para instrumentos agudos. El círculo de la clave abraza la segunda línea, que es la nota Sol. 
                La clave de <strong>Fa</strong> se usa para instrumentos graves. Los dos puntos encierran la cuarta línea, que es la nota Fa.
              </p>
            </div>
          </div>
        </section>
      </main>

      <footer className="mt-12 text-slate-400 text-sm pb-8">
        &copy; {new Date().getFullYear()} Pentagrama Maestro - Hecho con ❤️ para músicos principiantes
      </footer>
    </div>
  );
};

export default App;

import React, { useEffect, useRef } from 'react';
import { Vex } from 'vexflow';
import { MusicNote, Clef } from '../types';

interface MusicSheetProps {
  notes: MusicNote[];
  clef: Clef;
}

const MusicSheet: React.FC<MusicSheetProps> = ({ notes, clef }) => {
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!containerRef.current || notes.length === 0) return;

    // Clear previous render
    containerRef.current.innerHTML = '';

    const VF = Vex.Flow;
    const renderer = new VF.Renderer(containerRef.current, VF.Renderer.Backends.SVG);

    // Adjust size based on container or fixed width for 8 notes
    const width = 650;
    const height = 200;
    renderer.resize(width, height);

    const context = renderer.getContext();
    const stave = new VF.Stave(10, 40, width - 20);

    stave.addClef(clef).addTimeSignature('4/4');
    stave.setContext(context).draw();

    // Convert our internal notes to VexFlow notes
    const vfNotes = notes.map((n) => {
      return new VF.StaveNote({
        clef: clef,
        keys: n.keys,
        duration: n.duration,
      });
    });

    // Create a voice and add the notes
    const voice = new VF.Voice({ num_beats: 4, beat_value: 4 });

    // Automatic justification requires grouping by measures. 
    // For simplicity in a practice generator, we'll just fill voices or draw notes directly if simple.
    // However, VexFlow works best with formatters.

    // We adjust notes to fit in 4/4 - if total beats > 4, we might need multiple staves or just more measures.
    // Let's create multiple measures if needed, or simple fixed justification for 8 notes in a single long staff.

    // Justify and format to the stave width
    try {
        const formatter = new VF.Formatter().joinVoices([voice]).formatToStave([voice], stave);
        voice.draw(context, stave);
    } catch (e) {
        // If voice duration doesn't match 4/4 exactly, VexFlow might complain.
        // For a practice tool where we just want to see notes, we can force drawing or just render individual notes.
        // A better approach for a learner: just draw them in sequence.

        Vex.Flow.Formatter.FormatAndDraw(context, stave, vfNotes);
    }

  }, [notes, clef]);

  return (
    <div 
      id="music-canvas" 
      ref={containerRef} 
      className="flex justify-center items-center w-full"
    />
  );
};

export default MusicSheet;

import React from 'react';
import { GeneratorConfig, Clef } from '../types';

interface ControlsProps {
  config: GeneratorConfig;
  setConfig: React.Dispatch<React.SetStateAction<GeneratorConfig>>;
}

const Controls: React.FC<ControlsProps> = ({ config, setConfig }) => {
  const handleClefChange = (clef: Clef) => {
    setConfig(prev => ({ ...prev, clef }));
  };

  const handleToggle = (key: keyof GeneratorConfig) => {
    setConfig(prev => ({ ...prev, [key]: !prev[key] }));
  };

  const handleCountChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = parseInt(e.target.value);
    if (!isNaN(val) && val >= 1 && val <= 16) {
      setConfig(prev => ({ ...prev, count: val }));
    }
  };

  return (
    <div className="space-y-5">
      <div className="space-y-2">
        <label className="text-xs font-semibold text-slate-500 uppercase">Clave</label>
        <div className="flex gap-2">
          <button
            onClick={() => handleClefChange('treble')}
            className={`flex-1 py-2 rounded-lg border transition ${
              config.clef === 'treble' 
                ? 'bg-indigo-50 border-indigo-200 text-indigo-700 font-bold' 
                : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50'
            }`}
          >
            Sol
          </button>
          <button
            onClick={() => handleClefChange('bass')}
            className={`flex-1 py-2 rounded-lg border transition ${
              config.clef === 'bass' 
                ? 'bg-indigo-50 border-indigo-200 text-indigo-700 font-bold' 
                : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50'
            }`}
          >
            Fa
          </button>
        </div>
      </div>

      <div className="space-y-2">
        <label className="text-xs font-semibold text-slate-500 uppercase">Figuras Musicales</label>
        <div className="space-y-2">
          <label className="flex items-center gap-3 cursor-pointer group">
            <input 
              type="checkbox" 
              checked={config.includeRedondas} 
              onChange={() => handleToggle('includeRedondas')}
              className="w-4 h-4 text-indigo-600 rounded border-slate-300 focus:ring-indigo-500"
            />
            <span className="text-sm text-slate-700 group-hover:text-slate-900">Redondas (1/1)</span>
          </label>
          <label className="flex items-center gap-3 cursor-pointer group">
            <input 
              type="checkbox" 
              checked={config.includeBlancas} 
              onChange={() => handleToggle('includeBlancas')}
              className="w-4 h-4 text-indigo-600 rounded border-slate-300 focus:ring-indigo-500"
            />
            <span className="text-sm text-slate-700 group-hover:text-slate-900">Blancas (1/2)</span>
          </label>
          <label className="flex items-center gap-3 cursor-pointer group">
            <input 
              type="checkbox" 
              checked={config.includeNegras} 
              onChange={() => handleToggle('includeNegras')}
              className="w-4 h-4 text-indigo-600 rounded border-slate-300 focus:ring-indigo-500"
            />
            <span className="text-sm text-slate-700 group-hover:text-slate-900">Negras (1/4)</span>
          </label>
        </div>
      </div>

      <div className="space-y-2 pt-2">
        <label className="text-xs font-semibold text-slate-500 uppercase flex justify-between">
          <span>Cantidad de notas</span>
          <span className="text-indigo-600 font-bold">{config.count}</span>
        </label>
        <input 
          type="range" 
          min="1" 
          max="16" 
          step="1"
          value={config.count}
          onChange={handleCountChange}
          className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-indigo-600"
        />
      </div>
    </div>
  );
};

export default Controls;

import React, { useEffect, useRef } from 'react';
import { Renderer, Stave, StaveNote, Voice, Formatter } from 'vexflow';
import { MusicNote, Clef } from '../types';

interface MusicSheetProps {
  notes: MusicNote[];
  clef: Clef;
}

const MusicSheet: React.FC<MusicSheetProps> = ({ notes, clef }) => {
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!containerRef.current || notes.length === 0) return;

    // Clear previous render
    containerRef.current.innerHTML = '';

    // VexFlow 5.x uses named exports directly
    const renderer = new Renderer(containerRef.current, Renderer.Backends.SVG);

    // Adjust size based on container or fixed width for 8 notes
    const width = 650;
    const height = 200;
    renderer.resize(width, height);

    const context = renderer.getContext();
    const stave = new Stave(10, 40, width - 20);

    stave.addClef(clef).addTimeSignature('4/4');
    stave.setContext(context).draw();

    // Convert our internal notes to VexFlow notes
    const vfNotes = notes.map((n) => {
      return new StaveNote({
        clef: clef,
        keys: n.keys,
        duration: n.duration,
      });
    });

    // Create a voice and add the notes
    // For simplicity, we create a voice that matches the total duration of notes provided
    // but VexFlow 5.x is strict about durations. 
    // If the user selects 8 notes, we might exceed one 4/4 measure.

    try {
        // Attempt to format and draw as a single sequence
        // Formatter.FormatAndDraw is a convenient static method in VexFlow
        Formatter.FormatAndDraw(context, stave, vfNotes);
    } catch (e) {
        console.error("Error drawing notes:", e);
        // Fallback or manual drawing if formatting fails
        vfNotes.forEach(note => {
            note.setStave(stave);
            note.setContext(context).draw();
        });
    }

  }, [notes, clef]);

  return (
    <div 
      id="music-canvas" 
      ref={containerRef} 
      className="flex justify-center items-center w-full"
    />
  );
};

export default MusicSheet;

import React, { useState, useCallback, useEffect, useRef } from 'react';
import { Music, FileDown, RefreshCw, Info, Settings, Lightbulb } from 'lucide-react';
import MusicSheet from './components/MusicSheet';
import Controls from './components/Controls';
import { Clef, MusicNote, GeneratorConfig, NoteDuration } from './types';
import { TREBLE_NOTES, BASS_NOTES } from './constants';
import { GoogleGenAI } from '@google/genai';
import html2canvas from 'html2canvas';
import { jsPDF } from 'jspdf';

const App: React.FC = () => {
  const [measures, setMeasures] = useState<MusicNote[][]>([]);
  const [config, setConfig] = useState<GeneratorConfig>({
    clef: 'treble',
    includeRedondas: true,
    includeBlancas: true,
    includeNegras: true,
    count: 16 // No se usa directamente ahora, pero lo mantenemos por compatibilidad
  });
  const [aiTip, setAiTip] = useState<string>('');
  const [isGeneratingTip, setIsGeneratingTip] = useState(false);
  const sheetRef = useRef<HTMLDivElement>(null);

  const generateNotes = useCallback(() => {
    const possibleNotes = config.clef === 'treble' ? TREBLE_NOTES : BASS_NOTES;
    const durationOptions: {id: NoteDuration, beats: number}[] = [];
    if (config.includeRedondas) durationOptions.push({id: 'w', beats: 4});
    if (config.includeBlancas) durationOptions.push({id: 'h', beats: 2});
    if (config.includeNegras) durationOptions.push({id: 'q', beats: 1});

    if (durationOptions.length === 0) return;

    const newMeasures: MusicNote[][] = [];

    // Generamos 4 compases
    for (let i = 0; i < 4; i++) {
      const currentMeasure: MusicNote[] = [];
      let measureBeats = 0;

      while (measureBeats < 4) {
        // Filtramos duraciones que quepan en lo que queda del compás
        const validOptions = durationOptions.filter(d => d.beats <= (4 - measureBeats));
        if (validOptions.length === 0) break;

        const choice = validOptions[Math.floor(Math.random() * validOptions.length)];
        currentMeasure.push({
          keys: [possibleNotes[Math.floor(Math.random() * possibleNotes.length)]],
          duration: choice.id
        });
        measureBeats += choice.beats;
      }
      newMeasures.push(currentMeasure);
    }

    setMeasures(newMeasures);
    fetchTip(config.clef);
  }, [config]);

  const fetchTip = async (clef: Clef) => {
    setIsGeneratingTip(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `Como profesor de música para principiantes, dame un consejo muy corto (máximo 100 caracteres) sobre cómo leer mejor la clave de ${clef === 'treble' ? 'Sol' : 'Fa'}. Sé motivador.`;
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
      });
      setAiTip(response.text || '¡Sigue practicando!');
    } catch (error) {
      setAiTip("El secreto es la constancia. ¡A por ello!");
    } finally {
      setIsGeneratingTip(false);
    }
  };

  const exportPDF = async () => {
    if (!sheetRef.current) return;
    const canvas = await html2canvas(sheetRef.current, { scale: 2 });
    const imgData = canvas.toDataURL('image/png');
    const pdf = new jsPDF('l', 'mm', 'a4');
    const pdfWidth = pdf.internal.pageSize.getWidth();
    const pdfHeight = (canvas.height * pdfWidth) / canvas.width;

    pdf.setFontSize(20);
    pdf.text(`Práctica de 4 Compases: Clave de ${config.clef === 'treble' ? 'Sol' : 'Fa'}`, 15, 20);
    pdf.addImage(imgData, 'PNG', 10, 30, pdfWidth - 20, pdfHeight - 20);
    pdf.save(`partitura_4_compases.pdf`);
  };

  useEffect(() => {
    generateNotes();
  }, [generateNotes]);

  return (
    <div className="min-h-screen p-4 md:p-8 flex flex-col items-center">
      <header className="w-full max-w-5xl flex flex-col md:flex-row justify-between items-center mb-8 gap-4">
        <div>
          <h1 className="text-4xl font-bold text-slate-800 flex items-center gap-2">
            <Music className="text-indigo-600" size={36} />
            Pentagrama Maestro
          </h1>
          <p className="text-slate-500 mt-1">Practica lectura musical con 4 compases completos</p>
        </div>

        <div className="flex gap-3">
          <button
            onClick={generateNotes}
            className="flex items-center gap-2 bg-indigo-600 hover:bg-indigo-700 text-white px-5 py-2.5 rounded-lg font-semibold transition shadow-md"
          >
            <RefreshCw size={20} />
            Generar Nueva Partitura
          </button>
          <button
            onClick={exportPDF}
            className="flex items-center gap-2 bg-white border border-slate-200 hover:bg-slate-50 text-slate-700 px-5 py-2.5 rounded-lg font-semibold transition shadow-sm"
          >
            <FileDown size={20} />
            Guardar PDF
          </button>
        </div>
      </header>

      <main className="w-full max-w-5xl grid grid-cols-1 lg:grid-cols-4 gap-6">
        <aside className="lg:col-span-1 space-y-6">
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
            <h2 className="text-lg font-bold text-slate-800 mb-4 flex items-center gap-2">
              <Settings size={18} />
              Configuración
            </h2>
            <Controls config={config} setConfig={setConfig} />
          </div>

          <div className="bg-indigo-50 p-6 rounded-2xl border border-indigo-100">
            <h2 className="text-md font-bold text-indigo-800 mb-2 flex items-center gap-2">
              <Lightbulb size={18} />
              Consejo del Tutor
            </h2>
            <p className="text-indigo-900 text-sm italic min-h-[40px]">
              {isGeneratingTip ? 'Pensando un consejo...' : aiTip}
            </p>
          </div>
        </aside>

        <section className="lg:col-span-3">
          <div 
            ref={sheetRef}
            className="bg-white p-4 md:p-8 rounded-2xl shadow-lg border border-slate-100 flex flex-col items-center overflow-x-auto min-h-[350px]"
          >
            <div className="w-full flex justify-between items-center mb-6">
              <h3 className="text-slate-400 font-medium uppercase tracking-wider text-xs">Partitura de 4 compases</h3>
              <div className="flex gap-4">
                <span className="text-xs font-bold text-indigo-600 bg-indigo-50 px-2 py-1 rounded">4/4 TIME</span>
                <span className="text-xs font-bold text-emerald-600 bg-emerald-50 px-2 py-1 rounded">NIVEL INICIAL</span>
              </div>
            </div>

            <MusicSheet measures={measures} clef={config.clef} />

            <div className="mt-8 grid grid-cols-2 md:grid-cols-4 gap-4 w-full text-center">
               <div className="text-xs text-slate-500 bg-slate-50 p-2 rounded border border-slate-100">
                 <div className="font-bold">Compases</div>
                 <div>4</div>
               </div>
               <div className="text-xs text-slate-500 bg-slate-50 p-2 rounded border border-slate-100">
                 <div className="font-bold">Clave</div>
                 <div>{config.clef === 'treble' ? 'Sol' : 'Fa'}</div>
               </div>
               <div className="text-xs text-slate-500 bg-slate-50 p-2 rounded border border-slate-100">
                 <div className="font-bold">Figuras</div>
                 <div>{config.includeRedondas ? '🔴' : ''}{config.includeBlancas ? '⚪' : ''}{config.includeNegras ? '⚫' : ''}</div>
               </div>
