import React, { useEffect, useRef } from 'react';
import { Renderer, Stave, StaveNote, Voice, Formatter } from 'vexflow';
import { MusicNote, Clef } from '../types';

interface MusicSheetProps {
  measures: MusicNote[][];
  clef: Clef;
}

const MusicSheet: React.FC<MusicSheetProps> = ({ measures, clef }) => {
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!containerRef.current || measures.length === 0) return;

    // Limpiar renderizado previo
    containerRef.current.innerHTML = '';

    const renderer = new Renderer(containerRef.current, Renderer.Backends.SVG);

    // Ancho total para 4 compases
    const totalWidth = 800;
    const height = 200;
    renderer.resize(totalWidth, height);

    const context = renderer.getContext();
    const measureWidth = (totalWidth - 40) / 4;

    let currentX = 20;

    measures.forEach((measureNotes, index) => {
      const stave = new Stave(currentX, 40, measureWidth);

      // Solo el primer compás lleva clave e indicación de compás
      if (index === 0) {
        stave.addClef(clef).addTimeSignature('4/4');
      }

      stave.setContext(context).draw();

      const vfNotes = measureNotes.map((n) => {
        return new StaveNote({
          clef: clef,
          keys: n.keys,
          duration: n.duration,
        });
      });

      const voice = new Voice({ num_beats: 4, beat_value: 4 });
      voice.addTickables(vfNotes);

      new Formatter().joinVoices([voice]).formatToStave([voice], stave);
      voice.draw(context, stave);

      currentX += measureWidth;
    });

  }, [measures, clef]);

  return (
    <div 
      id="music-canvas" 
      ref={containerRef} 
      className="flex justify-center items-center w-full overflow-x-auto py-4"
    />
  );
};

export default MusicSheet;

