    pdf.addImage(imgData, 'PNG', 10, 30, pdfWidth - 20, pdfHeight - 20);
    pdf.save(`partitura_grand_staff.pdf`);
  };

  useEffect(() => {
    generateNotes();
  }, [generateNotes]);

  return (
